INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('20da29dd-e679-4f72-a337-374cb13dbc73', '[Tài liệu: Danh sách bộ môn trực thuộc Viện Công nghệ thông tin FBU] [Các bộ môn - Viện Công Nghệ Thông Tin]
#### Các học phần do Bộ môn Tin ứng dụng quản lý:
> Danh sách học phần bao gồm các môn tin học đại cương, lập trình, mạng, cơ sở dữ liệu, thương mại điện tử, an toàn thông tin, ERP, v.v.

- Tin học đại cương (Cho SV CNTT)
- Tin học 1 (Cho SV các ngành của FBU)
- Tin học 2 (Cho SV các ngành của FBU)
- Tin cơ sở
- Toán rời rạc ứng dụng cho Tin học
- Kiến trúc máy tính và Nguyên lý hệ điều hành
- Cấu trúc dữ liệu và giải thuật
- Nhập môn mạng máy tính
- Hệ cơ sở dữ liệu
- Lập trình hướng đối tượng (C++)
- Công nghệ phần mềm
- Hệ quản trị CSDL SQL Server
- Phân tích, thiết kế hướng đối tượng
