#### Các học phần do Bộ môn Tin ứng dụng quản lý:
- Ứng dụng Tin học trong Kế toán
- Ứng dụng Tin học trong Ngân hàng
- Ứng dụng Tin học trong Tài chính
- Ứng dụng Tin học trong Quản trị kinh doanh
- Lập trình trực quan Java
- Điện toán đám mây
- An toàn và bảo mật thông tin
- Lập trình trực quan C#
- Phát triển ứng dụng trên thiết bị di động
- Phần mềm mã nguồn mở và Linux
- Hệ thống hoạch định nguồn lực doanh nghiệp (ERP)
- Thiết kế Hệ thống thương mại điện tử
- Hệ thống ngân hàng lõi', '[-0.08320312,0.04336474,0.018044958,-0.017109308,-0.041275326,0.04643123,0.020515703,-0.06775792,-0.0020469408,0.08443024,0.055048373,-0.022967717,-0.023704559,0.016656261,0.049587164,-0.04808343,-0.048246983,0.07825246,-0.042531792,0.049114864,0.07992363,-0.07764039,0.028483678,-0.060314287,-0.0208905,-0.01711959,0.02423561,0.06867059,-0.07085832,-0.1397817,-0.033295337,0.05736306,-0.021613456,-0.030209398,0.0682981,-0.060824938,-0.042798378,0.032528043,0.01520972,0.007766661,-0.038757343,-0.026341977,0.007300694,-0.038873762,0.0173292,0.017235806,-0.07578627,-0.03209132,0.05453011,0.023395222,-0.04245061,0.026345238,0.07336334,0.033245698,0.0039855717,0.026215078,0.031617112,0.06461854,0.07387096,0.071195506,0.028966192,0.053371906,-0.115975045,0.13827765,0.08623845,0.063663535,0.004583547,-0.0040899306,-0.055166632,-0.012827332,-0.017234791,0.06096936,0.0036463127,0.072356224,-0.068226345,0.0701034,0.007738482,0.078483,-0.09093801,-0.011681183,-0.016517913,-0.019275665,-0.05071256,0.009661678,-0.028710507,0.0033017918,0.012222531,-0.02991174,-0.03919731,-0.032836873,-0.02882169,-0.046842914,0.046631575,-0.05473585,-0.021692207,-0.033512734,0.07179099,0.032134414,-0.006240958,0.095170796,-0.027112305,0.030509068,-0.031197252,-0.09622828,-0.013030097,-0.0007795602,0.054196242,-0.022080338,0.056050304,-0.028402781,-0.062027674,-0.015512256,0.02529938,-0.044284888,0.04657858,0.031705342,-0.03248863,-0.07033353,-0.018183975,0.033974353,0.04301585,0.009552748,-0.0011574101,0.015565012,0.052017566,-0.06420007,0.057230692,0.087104775,0.075840265,-0.022809066,0.05981159,-0.014114761,-0.009517188,-0.048460662,-0.018971046,-0.031857904,-0.048246972,-0.03848809,0.05594101,-0.01760862,-0.0039561973,-0.09592564,-0.0057373964,-0.08655816,0.0038949843,0.057631783,-0.060255025,0.03369357,-0.047193043,-0.05782662,-0.025721848,-0.035032146,0.09747397,0.0003705889,-0.006968684,0.0345526,-0.007399782,0.094277985,-0.0054406244,0.017852757,-0.07203688,-0.011