INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('e10fb213-765c-4236-8cd1-7ba31cf5a33c', '[Tài liệu: Các bộ môn thuộc Viện Kế toán - Kiểm toán FBU] [Các bộ môn - Viện Kế toán - Kiểm toán]
#### b) Nhiệm vụ cụ thể
- Xây dựng chương trình đào tạo, biên soạn giáo trình, tài liệu tham khảo, quỹ đề kiểm tra, thi, đề tài khóa luận tốt nghiệp.
- Chịu trách nhiệm về nội dung, chất lượng, tiến độ giảng dạy, học tập các học phần được giao.
- Cải tiến phương pháp giảng dạy, kiểm tra, đánh giá, tổ chức hoạt động học thuật.
- Nghiên cứu khoa học, thực hiện dịch vụ; phối hợp với cơ sở đào tạo, tổ chức hành nghề Kế toán, Kiểm toán.
- Xây dựng kế hoạch bồi dưỡng và quản lý đội ngũ giảng viên, cán bộ khoa học.
- Đề xuất hợp tác với đơn vị trong nước, nước ngoài.
- Tổ chức đánh giá công tác quản lý, hoạt động đào tạo của giảng viên.
- Quản lý cơ sở vật chất, thiết bị và các nhiệm vụ khác.', '[-0.088727795,0.04198203,0.011905423,-0.0020338723,-0.03479866,0.056813117,0.060580377,-0.08790505,0.023314733,0.08614886,0.033310883,-0.019535976,-0.03702535,0.017412283,0.031228948,-0.030877817,-0.047126535,0.062443722,-0.094098315,0.06168067,0.0770144,-0.04210055,0.020076344,-0.031521384,-0.025345072,-0.037877012,0.028515177,0.05126115,-0.08663162,-0.11383334,-0.061266858,0.03388037,-0.016917754,-0.044639774,0.04787072,-0.040612455,-0.031002032,0.050310697,0.0176894,0.019571088,-0.05041585,-0.03277896,-0.010944193,-0.050280523,0.0009608694,0.036352236,-0.06311551,-0.046254784,0.065666005,0.027461348,-0.05990964,0.013125321,0.05238298,0.05730674,0.0050566676,0.07940555,0.027635472,0.034768924,0.102329604,0.07612652,0.008322481,0.086508214,-0.15444744,0.17762548,0.11411772,0.05999311,-0.018533343,0.030957822,-0.048533823,-0.026763435,0.0068335794,0.04623751,0.010380527,0.026480962,-0.08189609,0.087714516,0.06374001,0.08135093,-0.09762584,-0.020971363,-0.011768493,-0.019319259,0.0030445459,-0.00602347,-0.037155,-0.03900121,0.031371873,-0.038713228,-0.050684277,-0.012903555,0.003367546,-0.04221174,0.016197367,-0.056368608,-0.012577543,-0.062140767,0.05401192,0.062956214,-0.024520023,0.072345085,-0.0035120659,0.028536584,-0.03578562,-0.07091204,-0.031801563,-0.01591886,0.037948366,-0.019925257,0.06435202,-0.01324476,-0.058304876,-0.032936845,0.051875368,-0.054824356,0.03325991,0.04236866,-0.012524175,-0.086420335,-0.036906343,0.022805315,0.037256412,-0.023439167,0.022786586,-0.005843293,0.029055512,-0.034407247,0.066750765,0.063796856,0.06533364,-0.03552512,0.06278439,-0.011583501,0.024212822,-0.03876418,-0.016409462,-0.04665035,-0.034890704,-0.04810374,0.07021927,-0.026294375,0.0100767305,-0.105866775,-0.024425745,-0.08684522,-0.0038936608,0.05752327,-0.09109329,0.027172677,-0.03918404,-0.06541744,-0.024809027,-0.00060038466,0.109015495,0.008670951,-0.01328408,0.03620961,-0.012747506,0.07115081,-0.029508375,