INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('c28e72d7-f44c-4854-b102-e2aa7fc1df78', '[Tài liệu: Kế hoạch tuyển sinh đào tạo trình độ thạc sĩ năm 2026] [THÔNG BÁO]
> Văn bản trình bày kế hoạch tuyển sinh thạc sĩ năm 2026 của Trường Đại học Tài chính - Ngân hàng Hà Nội: ngành đăng ký, điều kiện, hồ sơ, quy trình, thời gian, địa điểm, học phí.

Căn cứ Quyết định 2336/QĐ-TTg ngày 21/12/2010 của Thủ tướng Chính phủ về việc thành lập Trường Đại học Tài chính - Ngân hàng Hà Nội.
