INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('fcabba89-a4d5-4bf0-a18c-3d57bb48c5ca', '[Tài liệu: Kế hoạch tuyển sinh đào tạo trình độ thạc sĩ năm 2026] [II. ĐIỀU KIỆN XÉT TUYỂN]
### 1. Điều kiện về văn bằng
- Ứng viên đã tốt nghiệp hoặc đã đủ điều kiện công nhận tốt nghiệp đại học (hoặc trình độ tương đương trở lên) nhóm ngành phù hợp với ngành đăng ký xét tuyển.
- Đối với các ứng viên có văn bằng thuộc các nhóm ngành gần phải học bổ sung kiến thức được nhà trường quy định trước khi xét tuyển đầu vào (Phụ lục 2).
- Ứng viên có văn bằng đại học do cơ sở nước ngoài cấp phải được công chứng bằng tiếng Việt và kèm theo văn bằng công nhận, văn bằng của cơ quan khảo thí và kiểm định chất lượng Giáo dục - Bộ Giáo dục và Đào tạo.', '[-0.10638317,0.034167215,-0.003467751,-0.011709419,-0.02630661,0.04108724,0.034200612,-0.06675232,0.028680783,0.091761865,0.083190255,-0.018758139,-0.03171472,0.03048008,0.028769955,-0.035312213,-0.050124675,0.0581017,-0.055416793,0.049987618,0.06655807,-0.033071466,0.029940402,-0.034058042,-0.03860495,-0.030199962,0.042484086,0.078679934,-0.081690125,-0.12073057,-0.04089953,0.035696458,-0.014889704,-0.02002659,0.049664706,-0.06927505,-0.029230377,0.055629715,0.017576,0.040072218,-0.028177857,-0.049299106,-0.010541045,-0.06438248,0.028783025,0.013441374,-0.07664383,-0.06401684,0.05991771,0.022269191,-0.06613745,-0.016693903,0.055717822,0.073301025,0.023854878,0.0334063,-0.010986108,0.03498311,0.06986034,0.0835415,0.0010267938,0.07560598,-0.1332632,0.15384442,0.07523732,0.062074386,-0.012540267,2.5054118e-07,-0.026039043,-0.015943138,0.020591669,0.0486789,0.007029526,0.02373072,-0.06563748,0.0793936,0.025290433,0.08645971,-0.09260061,-0.053349897,-0.022225494,-0.01668384,-0.008789167,0.00024956875,-0.040198952,-0.029012047,0.0048824404,-0.022168333,-0.040619224,-0.01948897,0.00988697,-0.027009824,0.014580737,-0.052995317,-0.028030347,-0.06676281,0.040934842,0.027119705,-0.033712834,0.08159702,0.003566629,0.047687054,-0.039910078,-0.081415005,-0.057434503,-0.0051341634,0.052081596,-0.01947574,0.050606318,-0.012345705,-0.050517537,-0.041875187,0.043886047,-0.031745557,0.045175657,0.025491334,-0.02375227,-0.092597075,-0.05114776,0.03365219,0.044705886,0.014391551,0.008500705,-0.029472282,0.05238583,-0.03222475,0.042464703,0.07176891,0.057937272,-0.019499037,0.05270483,-0.0044219624,0.015289811,-0.034643754,-0.033730123,-0.055191554,-0.052824397,-0.028087394,0.059067294,-0.006874239,-0.0031031603,-0.10506335,-0.040369328,-0.09345436,-0.00037627446,0.07512549,