INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('4d4adf1a-c187-4628-ab64-a21a14fb5af4', '[Tài liệu: Kế hoạch tuyển sinh đào tạo trình độ thạc sĩ năm 2026] [II. ĐIỀU KIỆN XÉT TUYỂN]
### 2. Điều kiện về năng lực ngoại ngữ
Ứng viên có năng lực ngoại ngữ từ Bậc 3 trở lên theo Khung năng lực ngoại ngữ 6 bậc dùng cho Việt Nam. Ứng viên nộp minh chứng về trình độ ngoại ngữ theo yêu cầu của chương trình đào tạo tại thời điểm nộp hồ sơ.

Ứng viên đáp ứng yêu cầu này khi có một trong các văn bằng, chứng chỉ sau:
- Bằng tốt nghiệp trình độ đại học trở lên ngành ngôn ngữ nước ngoài, hoặc bằng tốt nghiệp trình độ đại học trở lên mà chương trình học được thực hiện bằng tiếng nước ngoài.
- Một trong các văn bằng hoặc chứng chỉ ngoại ngữ tương đương Bậc 3 trở lên theo khung năng lực ngoại ngữ 6 bậc dùng cho Việt Nam quy định tại Phụ lục I hoặc các chứng chỉ tương đương khác được Bộ Giáo dục và Đào tạo công bố, còn hiệu lực tính đến ngày đăng ký dự tuyển.', '[-0.114209935,0.034964237,-0.010180087,-0.0090759,-0.036970753,0.049652435,0.03491963,-0.08974699,0.020855052,0.08965596,0.0732258,-0.020036003,-0.037687264,0.03648149,0.031219488,-0.034550365,-0.06118548,0.06352193,-0.0681827,0.04590942,0.045927998,-0.053636484,0.018422367,-0.03632791,-0.03702914,-0.024510218,0.04084173,0.074074775,-0.079454355,-0.13360152,-0.044344798,0.037203807,-0.025808964,-0.031994034,0.0652351,-0.06727518,-0.035200745,0.07361423,0.029408026,0.047693286,-0.026268147,-0.04189366,0.016088746,-0.059833784,0.024536055,0.039458286,-0.077294245,-0.047439214,0.07184159,0.025607707,-0.08804481,-0.024643725,0.043595377,0.061063148,0.021643069,0.017758576,-0.0013655383,0.00882638,0.06803761,0.08482101,0.013997365,0.07357196,-0.14987957,0.15898918,0.082370624,0.045720108,-0.02547898,0.0037555445,-0.024992883,-0.010373084,0.028714186,0.03842473,0.0047067935,0.017731283,-0.053096272,0.06524038,0.047252335,0.074753374,-0.09087761,-0.05052089,-0.024476461,-0.02032111,-0.014335284,0.00076918566,-0.032839477,-0.035715036,0.008287389,-0.022638248,-0.025464112,-0.011675472,0.011621266,-0.03035005,0.030136693,-0.047564965,-0.02957009,-0.06763912,0.048167557,0.035761695,-0.027719835,0.07847151,-0.009327442,0.04887738,-0.014938165,-0.09235664,-0.05595351,-0.0029131358,0.04496146,-0.024420587,0.061738692,-0.009422647,-0.04122083,-0.056508884,0.054084662,-0.04399103,0.0643822,0.036179762,-0.015160985,-0.08257908,-0.03445474,0.03169266,0.03900566,0.012389018,0.0050211153,-0.03384071,0.0394258,-0.025249036,0.036599353,0.064470336,0.05946206,-0.018552773,0.061244085,-0.004341782,0.020393692,-0.035399474,-0.035981055,-0.049036734,-0.052128047,-0.009007497,0.062181678,-0.023848305,-0.011837293,-0.095138