### Giá trị cốt lõi
- Phát triển học thuật mang tính dân chủ cao;
- Mở rộng cơ hội cho người học;
- Không tiêu cực học đường;
- Minh bạch, thượng tôn pháp luật và cam kết;
- Chuyên nghiệp, tinh gọn và hiệu quả;
- Năng động, sáng tạo và cẩn trọng;
- Thích ứng đa dạng để vượt khó.', '[-0.09319239,0.047345184,0.015088323,-0.017200802,-0.06972042,0.08368937,0.06693689,-0.082197055,-0.012169131,0.07219333,0.05766688,-0.039856546,-0.03412864,0.011898337,0.04092831,-0.02662227,-0.057067517,0.07803184,-0.075633734,0.042934615,0.060963213,-0.034296036,0.03649161,-0.04258696,-0.015070606,-0.039549734,0.027271403,0.05475454,-0.046384126,-0.09604732,-0.046108257,0.041384798,-0.0039401143,-0.04265186,0.055360697,-0.06224075,-0.05860165,0.053711616,0.036744818,0.023588266,-0.030193875,-0.014841287,0.05342946,-0.057611514,0.022370012,0.021828152,-0.064660884,-0.07078448,0.043775,0.017053217,-0.0812734,0.020355301,0.04393893,0.04020805,0.013922223,0.052627154,0.04256619,0.05213742,0.08860679,0.09019972,0.044890523,0.06477753,-0.13515475,0.1334518,0.07659758,0.056167815,-0.038096704,0.004319175,-0.028389271,-0.013263707,0.007150043,0.061080173,-0.0033923883,0.044294383,-0.047351014,0.05407779,0.044521786,0.07652971,-0.103202425,-0.020253563,-0.024585648,-0.023802254,-0.03158754,0.019575315,-0.054306846,0.0023434332,0.02507702,-0.02131637,-0.017867934,-0.011205091,-0.04276336,-0.015051033,0.040066514,-0.029971872,-0.0034637374,-0.058134973,0.048740968,0.068255946,-0.018903196,0.07986076,0.019026231,0.039642658,-0.02079836,-0.056727573,-0.054509286,-0.0063183126,0.0052221976,-0.026427172,0.046741545,-0.013137545,-0.06283677,-0.042953257,0.027980493,-0.0350286,0.045543537,0.040088713,-0.021682398,-0.07375346,-0.03688176,0.036644474,0.032213733,-0.0261546,-0.033684287,-0.008553376,0.055618893,-0.021296611,0.09962342,0.052329056,0.04206017,-0.016811537,0.07393402,-0.005080553,0.018839143,-0.049017783,-0.054551188,-0.063684344,-0.03690233,-0.015506863,0.06231244,-0.047595307,-0.010935137,-0.1183773,-0.0059817648,-0.09500595,0.028026735,0.055296022,-0.085603684,0.021688059,-0.03205184,-0.057028715,-0.011714755,-0.01843492,0.08188289,-0.011320003,-0.002093604,0.018409194,-0.015816163,0.091226764,-0.04097164,0.020474538,-0.05775953,-