INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('baca2ec1-70e8-4147-87cc-fd4583c3209f', '[Tài liệu: Kế hoạch tuyển sinh đào tạo trình độ thạc sĩ năm 2026] [PHỤ LỤC 4: YÊU CẦU BÀI LUẬN ĐỊNH HƯỚNG NGHIÊN CỨU]
> Quy định về bài luận: ngôn ngữ, độ dài, nội dung bắt buộc.

1. Ngôn ngữ viết: tiếng Việt.
2. Độ dài bài luận: khoảng 600 từ (+/- 10%).
3. Nội dung chính cần có:
   - Giới thiệu khái quát về bản thân
   - Điểm mạnh, điểm yếu
   - Thành tích học tập, nghiên cứu khoa học
   - Nghề nghiệp hiện tại
   - Mục đích, lý do đăng ký dự tuyển
   - Lý do chọn ngành học
