INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('b264bef6-70b7-4abd-95e5-7a2210ae3c99', '[Tài liệu: Lịch sử phát triển Trường Đại học Tài chính - Ngân hàng Hà Nội] [Lịch sử phát triển]
### 1. Khái quát chung
> Thông tin thành lập và sứ mệnh.

Trường Đại học Tài chính - Ngân hàng Hà Nội hoạt động theo quy chế trường đại học tư thục, được thành lập theo **Quyết định số 2336/2010/QĐ-TTg ngày 21 tháng 12 năm 2010** của Thủ tướng Chính phủ.

