INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('448161b7-7d21-47ef-993d-19c5890e7bc3', '[Tài liệu: Lịch sử phát triển Trường Đại học Tài chính - Ngân hàng Hà Nội] [Lịch sử phát triển]
#### 2.2 Các giải pháp cơ bản
- Liên kết doanh nghiệp để hướng nghiệp, hỗ trợ việc làm.

##### 2.2.2 Đầu tư xây dựng trường sở khang trang
> Khuôn viên đẹp, hạ tầng hiện đại, phòng thực hành, thể thao, ký túc xá.

- Khuôn viên rộng >10 ha, cảnh quan kết hợp thiên nhiên.
- Hạ tầng giao thông, điện, nước theo tiêu chuẩn Việt Nam và quốc tế.
- Phòng thực hành hiện đại, tin học hóa, đào tạo trực tuyến, video-conference, kết nối băng thông rộng.
- Hạ tầng thể thao: sân bóng đá, bóng chuyền, bóng rổ, cầu lông, bể bơi, tennis, bóng bàn, thể dục dụng cụ, nhà hát, rạp chiếu phim.', '[-0.07751609,0.058809914,0.01981868,-0.0059506004,-0.024428917,0.060275856,0.04067897,-0.06446034,0.0063021705,0.078739196,0.060536932,-0.047508143,-0.029047871,0.022275293,0.014795347,-0.045161474,-0.05643547,0.07153013,-0.08459245,0.041295737,0.07308944,-0.051075082,0.014041326,-0.043078247,-0.008957897,-0.036288597,0.023718763,0.059102077,-0.059240103,-0.10156926,-0.058177065,0.054400727,0.025750585,-0.04794702,0.036626678,-0.109760895,-0.06793409,0.03994136,-0.00096956,0.010529812,-0.037542146,-0.029893529,0.018530222,-0.042416435,-0.000874594,0.02769869,-0.07870671,-0.055167347,0.07246317,0.014678549,-0.077643536,0.02778823,0.040232815,0.025286209,0.018087853,0.06122117,0.03739825,0.048443437,0.0774463,0.07828645,0.010897582,0.06820703,-0.15822136,0.16208023,0.09569997,0.059056588,-0.014391903,0.050162144,-0.008503728,-0.01267357,0.0063292934,0.023367262,0.011576135,0.04344571,-0.053787872,0.06222708,0.018910086,0.08730305,-0.10338969,-0.03872805,-0.012508493,-0.027812257,-0.04368841,0.037714474,-0.040378913,-0.0058005396,0.019395413,-0.02642552,-0.020169118,-0.031746723,-0.0074869357,-0.040324364,0.009715935,-0.055416953,-0.0035541859,-0.06625951,0.04380882,0.033529803,-0.0059160464,0.074274436,0.014781952,0.046928167,-0.001236375,-0.07980891,-0.051851425,-0.01448487,0.024702284,-0.029582426,0.04041215,0.0139583275,-0.072107784,-0.046565596,0.04896427,-0.02364421,0.06066097,0.06652538,-0.016307894,-0.047118068,-0.03713158,0.005524639,0.035481215,-0.016201695,-0.0031363938,-0.032700904,0.04449218,-0.013489488,0.08305343,0.067096435,0.05376234,-0.020450061,0.048870903,-0.012617604,0.00020478062,-0.029409835,-0.03268866,-0.07873269,-0.03212921,-0.03953031,0.05756303,-0.034930844,0.013751492,-0.12024155,-0.02315119,-0.09463633,0.031470463,0.08615278,-0.09173978,0.024112765,-0.015004161,-0.049221285,-0.013417367,-0.039194178,0.0383