INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('27a91a03-e3c0-4eaa-b14f-c4a3e2ddf12d', '[Tài liệu: Giới thiệu Trường Đại học Tài chính - Ngân hàng Hà Nội] [Thông tin liên hệ FBU]
> Địa chỉ, điện thoại, email, website và các liên kết nhanh của Trường Đại học Tài chính - Ngân hàng Hà Nội.

- **Trụ sở chính:** Xã Tiền Phong – H. Mê Linh – TP. Hà Nội
- **Cơ sở đào tạo 2:** Số 31 Dịch Vọng Hậu, Quận Cầu Giấy, TP. Hà Nội
- **Điện thoại:** [024 3793 1340](tel:02437931340) hoặc [024 3793 1341](tel:02437931341)
- **Email:** [tuyensinh@fbu.edu.vn](mailto:tuyensinh@fbu.edu.vn)
- **Website chính thức:** [https://www.fbu.edu.vn](https://www.fbu.edu.vn)

