INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('822d6073-270f-4128-ab09-da70ea18d81c', '[Tài liệu: Hỏi đáp về Giáo dục thể chất, Quốc phòng - An ninh tại FBU] [Giáo dục thể chất và Quốc phòng - An ninh]
### Câu hỏi 1: Giáo dục thể chất và Quốc phòng - An ninh có được tính vào GPA tích lũy để xét loại bằng không?
**Trả lời:**  
Chào bạn, câu hỏi này rất nhiều sinh viên quan tâm. Theo quy định của Trường Đại học Tài chính – Ngân hàng Hà Nội, **các môn Giáo dục thể chất (GDTC) và Giáo dục Quốc phòng – An ninh (GDQP-AN) không được tính vào điểm trung bình chung tích lũy (GPA)** để xét loại bằng tốt nghiệp (Xuất sắc, Giỏi, Khá, Trung bình).

Cụ thể:  
- Bạn chỉ cần **hoàn thành đủ số tín chỉ** của các môn GDTC và GDQP-AN (thường là qua điểm đạt yêu cầu).  
- Những môn này không ảnh hưởng đến GPA, nhưng **bắt buộc phải qua** mới được xét tốt nghiệp.', '[-0.10331609,0.026564496,0.00026823167,-0.02562835,-0.03588342,0.068169974,0.059194367,-0.041697122,0.012721958,0.08295302,0.058122188,-0.008308836,-0.02549395,0.022331648,0.01046898,-0.03989606,-0.057103742,0.069740914,-0.083737105,0.056171075,0.07648216,-0.049198944,0.024810115,-0.045867812,-0.038292103,0.0035520233,0.03428534,0.0313476,-0.07110552,-0.11913895,-0.050893586,0.031463765,0.0108301295,-0.073673025,0.076181784,-0.07434301,-0.04220189,0.06648461,0.01150459,0.017404074,-0.014125814,-0.05565411,0.03041521,-0.034301,0.01228137,0.0045659575,-0.06324489,-0.0513983,0.052172244,0.011550818,-0.065463856,0.016917784,0.06724403,0.0445691,0.0026956021,0.072291,0.044711642,0.048384722,0.06498252,0.100954264,-0.00890899,0.06626885,-0.15969066,0.15299055,0.09101056,0.054501224,-0.026970385,0.023346335,-0.0093281865,-0.011798292,0.00048513108,0.014474009,-0.02625625,0.0205007,-0.0852117,0.09912498,0.033186186,0.1192451,-0.04383825,-0.046813462,-0.044752132,-0.011530283,-0.011608962,0.02936545,-0.02910048,-0.01687327,0.044289432,-4.1498e-05,-0.051162735,-0.0077505247,0.0001443315,-0.036959693,0.0078289565,-0.048449963,-0.0032636097,-0.039304666,0.030359084,0.07133027,-0.048041724,0.07874859,0.013106563,0.030385097,-0.0016542816,-0.056118123,-0.06284472,0.0008434953,0.032940008,-0.03393668,0.03246893,-0.015131581,-0.045476373,-0.04154554,0.07166391,-0.021188108,0.043247458,0.036307987,0.015034568,-0.0762913,-0.02777103,0.019566596,0.03479774,-0.0053540557,0.0024022195,-0.00017038407,0.05891231,-0.0182683,0.07193639,0.06020623,0.059710357,-0.021709599,0.07469993,0.011475865,0.031498984,-0.029099358,-0.05339681,-0.058005847,-0.030770792,-0.03874885,0.0392622,-0.022209765,-0.007442864,-0.092677526,0.0036398498,-0.056022067,0.0011174863,0.064856805,-0.06785847,0.027874658,-0.042950485,-0.06966824,-0.013740916,-0.011979428,0.0510589,0.03410224,-0.016453248,-0.0044571916,0.0178805