INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('e85887c9-ccca-4ca0-975f-4f335179dec0', '[Tài liệu: Giới thiệu chung Viện Tài chính - Ngân hàng FBU] [Giới thiệu chung - Viện Tài Chính Ngân Hàng]
### I. Quá trình hình thành và phát triển
Viện Tài chính – Ngân hàng được thành lập cùng ngày với Trường (21/12/2010). Từ khi thành lập, Viện được giao quản lý đào tạo 2 chuyên ngành: **Tài chính Doanh nghiệp** và **Ngân hàng thương mại**.

Đội ngũ giảng viên 100% có trình độ thạc sĩ trở lên, tham gia đào tạo các trình độ: Đại học chính quy, Đại học chính quy chất lượng cao, Đại học liên thông chính quy, Thạc sĩ chính quy.

Đến năm 2021, Viện đã tuyển sinh được 10 khóa, 6 khóa đã ra trường. Gần 100% sinh viên có việc làm, trên 80% làm đúng nghề. Nhiều sinh viên trở thành cán bộ cốt cán của ngân hàng, cơ quan, doanh nghiệp.

Viện đã nhiều lần được nhận Bằng khen của Hiệu trưởng và Bộ trưởng Bộ GD&ĐT.', '[-0.099240616,0.036397934,0.007769192,-0.002323684,-0.022326043,0.03972368,0.045722608,-0.060145084,0.03266441,0.061904564,0.061473086,-0.043650903,-0.021501211,0.0030990283,0.010358042,-0.03959366,-0.04969967,0.06302252,-0.11138026,0.05061837,0.069697425,-0.065816365,0.036151122,-0.018815344,-0.028169116,-0.027524982,0.038152244,0.056089293,-0.07212016,-0.12487276,-0.04375861,0.03381941,-0.005367222,-0.068315975,0.05350111,-0.07115777,-0.02380816,0.07577692,0.03894393,0.05079092,-0.038132153,-0.040399052,0.023245014,-0.059610672,0.032036267,0.010464345,-0.077625215,-0.060771424,0.0827389,0.016850071,-0.067858264,0.0048065158,0.06660698,0.04555364,0.008326702,0.063751176,0.026388178,0.02452232,0.08214814,0.06640841,0.016643355,0.06517109,-0.14462656,0.12737313,0.10394614,0.046993334,-0.037195656,0.00956874,-0.008168874,-0.0018501946,0.022966519,0.0483115,0.038480606,0.036846716,-0.065770894,0.074751765,0.054207884,0.079031445,-0.08159868,-0.042356573,-0.030723685,-0.019170348,0.016966557,-0.00666388,-0.01009973,-0.018590167,0.03487224,-0.018317878,-0.026257362,-0.029740497,0.00055309455,-0.04432096,0.021888804,-0.038257156,-0.030275438,-0.040555514,0.03243849,0.083428554,-0.06003414,0.07471573,-0.0001718535,0.03436749,-0.015341873,-0.071262136,-0.060818482,-0.0054414724,0.050144937,-0.02532603,0.030661998,-0.020688478,-0.062243335,-0.043041438,0.04241506,-0.029774448,0.033694305,0.02875468,-0.014514377,-0.0788251,-0.05543168,0.029759822,0.028287865,0.0024506825,0.007859017,-0.046101373,0.04478205,-0.024394132,0.06994618,0.06572523,0.04801324,-0.0049740113,0.06334325,-0.011412459,0.025881637,-0.03660599,-0.039352525,-0.058408648,-0.02987521,-0.05249676,0.05979712,-0.030734334,0.015617513,-0.09708669,-0.019777056,-0.09061684,0.0059304563,0.052924547,-0.09822,0.029120555,-0.04306703,-0.05486492,-0.0050071278,-0.016285429,0.074789345,7.630714e-05,-0.01948756,0.026383612,-0.0008121554,0.06269