### 5. Định hướng phát triển
Mở rộng mạng lưới hợp tác quốc tế, đổi mới nội dung và phương thức đào tạo, gắn lý thuyết với thực tiễn, ứng dụng công nghệ số. Phát triển đội ngũ giảng viên chất lượng cao, đẩy mạnh nghiên cứu khoa học và trao đổi học thuật.', '[-0.0860115,0.03824732,0.0077471156,-0.0074002384,-0.050285894,0.07738868,0.06495436,-0.051721733,0.00691377,0.060292333,0.04122556,-0.043092307,-0.023110064,0.009732728,0.041990746,-0.040132083,-0.05989146,0.08671778,-0.06863914,0.03091293,0.06916938,-0.035787165,0.04832615,-0.026243022,-0.045218945,-0.05533576,0.03778035,0.05643256,-0.04600792,-0.12060141,-0.0461222,0.033942647,-0.0036339255,-0.05335236,0.053150285,-0.060604546,-0.033264454,0.03844535,0.04354714,0.037104484,-0.040043153,-0.043538313,0.024547197,-0.04045346,0.028855808,-0.007289972,-0.08362563,-0.051407583,0.06275639,0.03552608,-0.060880676,-0.017031077,0.043065894,0.045266975,0.0045962995,0.056771055,0.035281587,0.04556507,0.0930339,0.07515279,0.013271595,0.083407134,-0.14212586,0.13249935,0.08913287,0.06541211,-0.01930643,0.0034601495,-0.05058546,-0.02208063,0.032040264,0.061570764,-0.013729328,0.044441506,-0.048166465,0.067605026,0.02344103,0.054508198,-0.06631939,-0.008959681,-0.03802842,0.005096361,-0.027391266,2.8999357e-06,-0.034809187,-0.012725638,0.031236963,-0.02289522,-0.04753961,-0.0053770863,-0.021359675,-0.029674642,0.025699103,-0.058945425,-0.03263501,-0.059576686,0.03616474,0.04799249,-0.03680494,0.090233356,0.0022443703,0.045578435,-0.014138692,-0.07040576,-0.025641005,-0.014492831,0.022850651,-0.020378795,0.06372169,-0.017988842,-0.08162327,-0.036104877,0.045610383,-0.024050362,0.03990131,0.04810831,-0.017634211,-0.08307946,-0.033712577,0.029026587,0.052132476,-0.025008816,-0.0043563256,-0.017017772,0.059525445,-0.036322232,0.067125194,0.04591332,0.060210466,-0.010521913,0.045432754,-0.015322918,0.01297022,-0.044441815,-0.04480604,-0.06018615,-0.032996934,-0.027771672,0.045247003,-0.03962055,0.012965594,-0.1124491,-0.003387036,-0.08255596,0.0032069776,0.05