INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('e3f01867-a16d-41a0-aa30-456533b7b5ba', '[Tài liệu: Danh sách các trường đối tác quốc tế của FBU] [Các trường đối tác - FBU]
| Đối tác | Xếp hạng / Điểm nổi bật |
|---------|--------------------------|
| **Đại học Tài chính trực thuộc Chính phủ Liên bang Nga (FA)** | EduRank 2025: hạng 21 tại Nga. SCImago 2021: hạng 265 toàn cầu (Kinh tế, Tài chính). Lâu đời, uy tín, trực thuộc Chính phủ Nga, thành lập 1919. |
| **Đại học York (Vương quốc Anh)** | #20 UK (Times & Sunday Times 2025). #10 về chất lượng nghiên cứu. Thành viên Russell Group. |
| **Đại học Birmingham City (Anh)** | Top 500-600 thế giới (THE 2022). Khoa Kinh doanh được ACCA chứng nhận Bạch kim. |
| **Đại học Gia Hưng, Chiết Giang (Trung Quốc)** | #355 Trung Quốc (2023), #24 tỉnh Chiết Giang. 1.720 giảng viên, >16.900 sinh viên. |
| **Đại học Ngoại thương Liên bang Nga** | #3 lĩnh vực Kinh tế & Tài chính, #9 pháp lý. Bắt buộc học hai ngoại ngữ, hỗ trợ thực tập và việc làm. |
| **Đại học Pyeongtaek (Hàn Quốc)** | #1 đại học xuất sắc nhất Hàn Quốc do Chính phủ công nhận. Được chỉ định tiếp nhận du học sinh. Kết hợp với Samsung, LG. |
| **Đại học Kinh tế Quốc gia Plekhanov (Nga)** | #701-750 thế giới, #25 Nga. Lâu đời nhất, quy mô lớn nhất Nga, gần 120 năm. |
| **Đại học Help (Malaysia)** | Học viện đầu tiên trên thế giới cấp bằng Kinh tế của ĐH London từ 1986. Hơn 2.000 sinh viên nhận bằng ĐH London, 40 bằng First Class Honours. Hợp tác với LSE, ĐH Birmingham, Cardiff, Queensland, Melbourne, Sydney, ANU. |
| **Đại học Công nghệ Queensland (Úc)** | #4 Úc, #40 thế giới (QS 2025). #5 Úc, #43 thế giới (U.S. News 2025-2026). Thành viên Universitas 21, APRU, edX. |
| **Đại học Khai Nam (Đài Loan)** | #84 quốc gia. >90% giảng viên từ Mỹ, Châu Âu. Hợp tác với Massachusetts (Mỹ), Waseda (Nhật), Tasmania (Úc). |
| **Đại học Lĩnh Đông (Đài Loan)** | Xếp hạng "A+" trong 10 năm liên tiếp. Hợp tác với Mỹ, Úc, Argentina, Chile, Đức, Ý, Nhật, Hàn. |
| **Đại học Granada (Tây Ban Nha)** | #278 ARWU 2018, #3 Tây Ban Nha. Lớn thứ 4 Tây Ban Nha, ~56.000 sinh viên (11% quốc tế). |
| **Đại học Sư phạm Nam Ninh (Trung Quốc)** | #305 (tùy bảng). Quan hệ đối tác với 65 tổ chức từ 20 quốc gia. Hợp tác ASEAN; Trung tâm Ngôn ngữ và Văn hóa Thái Lan, trung tâm tiếng Trung tại Indonesia và Thái Lan. |
| **Đại học Sư phạm Liêu Ninh (Trung Quốc)** | #181 toàn quốc. Quan hệ với 118 trường ĐH và tổ chức từ 23 quốc gia. Tiếp nhận >1000 sinh viên nước ngoài/năm. |
| **Đại học Tịnh Nghi (Đài Loan)** | Hợp tác với hàng trăm đại học quốc tế (Mỹ, Nhật, Hàn, Đức, Pháp, Ý). |', '[-0.09417504,0.05374212,-0.0014366797,0.0036386023,-0.0036049495,0.03938018,0.010481578,-0.072391145,-0.012984605,0.07268152,0.074277006,-0.01618691,0.005719122,0.008625948,-0.0010165195,-0.021027897,-0.06650466,0.0182844,-0.110814124,0.04545462,0.09061552,-0.026195483,0.016204668,-0.048541434,-0.0042659864,-0.024917189,0.048457887,0.0659002,-0.096585475,-0.13836335,-0.027174909,0.03382252,0.003459917,-0.004084224,0.06062656,-0.06884963,-0.0052808993,0.053865325,0.03816651,0.022526437,-0.03517485,-0.029983245,-0.005809048,-0.036780793,0.005465218,0.034348127,-0.07715488,-0.04306423,0.07595068,0.014940983,-0.065215744,0.012599232,0.06609833,0.04530359,-0.018231504,0.04948819,0.02401579,0.040182687,0.10552434,0.06520998,0.02093652,0.043444358,-0.14310092,0.15875633,0.075060084,0.048517816,-0.039394524,0.009525602,-0.004270567,-0.0113295885,0.009286886,-0.0017894268,0.015237916,0.049907744,-0.06423917,0.0769822,0.048596952,0.054829285,-0.08307775,-0.027037248,-0.04036162,-0.027420692,-0.012620971,0.022769608,-0.034983065,-0.026941963,0.0246925,-0.029666904,-0.050077926,-0.05761652,0.00023038565,-0.043307014,0.03935189,-0.05584127,-0.03511746,-0.061595157,0.035535272,0.046916943,-0.006476959,0.08454637,-0.00082696974,0.057261012,0.011017986,-0.04900089,-0.05056779,-0.028693328,0.046465464,-0.0011948337,0.042954296,-0.036205325,-0.052090917,-0.038885303,0.019505622,-0.0059366664,0.037809413,0.032794204,-0.018537777,-0.0644076,-0.07223012,-0.0035886865,0.032670893,0.018010138,-0.011602551,-0.04096732,0.027956124,-0.015949003,0.06538207,0.07558284,0.0548922,-0.012136921,0.069893554,0.0023544861,0.01074558,0.0026349183,-0.052146714,-0.025923364,-0.03182114,-0.041941553,0.073428206,-0.03846804,-0.024348056,-0.09129341,-0.042593446,-0.10527432,0.014587574,0.06790751,-0.1098068,0.029322546,-0.03819877,-0.04631685,-0.007050107,-0.026961911,0.08377482,0.029746085,-0.026