INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('23222cda-f8d2-4ca4-949a-11972febc9f3', '[Tài liệu: Hỏi đáp về thủ tục hoãn thi tại FBU] [Hoãn thi]
### Câu hỏi: Hoãn thi thì hoãn được bao lâu và nộp đơn ở đâu?
**Trả lời:**  
Chào bạn, đối với trường hợp không thể tham gia kỳ thi đúng lịch vì lý do bất khả kháng (ốm đau, việc gia đình đột xuất...), bạn có thể làm đơn xin hoãn thi. Thủ tục cụ thể như sau:

1. **Nơi nộp đơn:** Bạn mang đơn xin hoãn thi (có xác nhận của cố vấn học tập hoặc giấy tờ chứng minh lý do) nộp trực tiếp tại **Phòng Khảo thí, tầng 2 cơ sở 31 Dịch Vọng Hậu**. Nên nộp trước ngày thi ít nhất 3 ngày làm việc để được xử lý kịp thời.', '[-0.08672957,0.039682224,0.014534265,-0.01907772,-0.037502002,0.054256413,0.05732726,-0.07457691,0.019257866,0.067326345,0.091629,-0.013322994,-0.018844116,0.015758587,0.0061900713,-0.044830766,-0.058302414,0.066331215,-0.09331727,0.04276264,0.07954174,-0.044757828,0.017763576,-0.0329684,-0.027917631,-0.01446317,0.047718935,0.048757367,-0.05833268,-0.14690925,-0.052799597,0.038898915,0.0077832555,-0.04796404,0.0704492,-0.076847896,-0.010524198,0.06595832,0.03730682,0.042895805,-0.031688757,-0.04121326,0.0056897365,-0.021094656,0.015481827,0.009388578,-0.07839396,-0.04443389,0.069901966,0.017708069,-0.073115386,0.020577855,0.051645707,0.045734387,0.0041219983,0.037344687,0.03859547,0.034032434,0.07046092,0.06623116,0.011332418,0.06740738,-0.14399877,0.1559826,0.11023485,0.059955854,-0.00684192,0.0317912,0.0050622094,-0.0068173683,0.025225872,0.028940117,0.006128396,0.037898604,-0.055107523,0.060679786,0.0594278,0.08272321,-0.11205178,-0.015998373,-0.029305208,-0.021565111,-0.012510736,0.014476447,-0.029445563,-0.016924204,0.017840967,-0.017629387,-0.031267952,-0.036339313,0.021163037,-0.035076622,-0.013408626,-0.06033728,-0.011666728,-0.067113094,0.055488754,0.060571764,-0.05398279,0.060465485,-0.0036732955,0.023538634,-0.028339935,-0.08996975,-0.06262897,-0.015204961,0.02976512,-0.016193256,0.023170572,0.013219236,-0.050221372,-0.033499494,0.05807443,-0.02517974,0.042574458,0.039672013,0.002932187,-0.07982617,-0.05918644,0.009431578,0.033342663,-0.015150569,0.011406632,-0.0049945093,0.05348899,-0.002888734,0.05861424,0.056158103,0.044573467,-0.05027902,0.078854024,-0.008907472,0.032519706,-0.06632323,-0.041571967,-0.04539216,-0.03421385,-0.05607991,0.060103934,-0.021489287,0.013592223,-0.11504989,-0.03945249,-0.0921616