INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('4865018c-52a6-4d6f-81b3-089183050a8d', '[Tài liệu: Hỏi đáp về thủ tục hoãn thi tại FBU] [Hoãn thi]
### Câu hỏi: Hoãn thi thì hoãn được bao lâu và nộp đơn ở đâu?
2. **Thời gian hoãn được:** Bạn sẽ được **thi lại vào lần thi gần nhất** của môn học đó (thường là đợt thi lại hoặc đợt thi cùng môn trong học kỳ tiếp theo). Không có giới hạn số lần hoãn, nhưng mỗi lần đều cần lý do chính đáng.

3. **Lưu ý quan trọng:** Nếu không hoãn mà bỏ thi, bạn sẽ bị điểm 0 và phải học lại môn đó (không được thi lại miễn phí). Vì vậy, hãy chủ động làm đơn hoãn nếu không thể dự thi.

Nếu còn thắc mắc, bạn có thể đến trực tiếp phòng khảo thí vào giờ hành chính để được hướng dẫn cụ thể hơn.', '[-0.097955324,0.031780384,0.0026548533,-0.010164326,-0.031276982,0.055959914,0.057118595,-0.07118726,0.031820033,0.07575594,0.065352604,-0.024836909,-0.028051313,0.02987597,0.036037266,-0.04111642,-0.073611565,0.07772028,-0.11360165,0.048606265,0.07459718,-0.03549323,0.020074897,-0.016372913,-0.030651165,-0.018293642,0.036183544,0.051976595,-0.031419545,-0.12800327,-0.0704779,0.0334956,-0.0036799102,-0.058776993,0.030481683,-0.07250485,-0.032028627,0.057006232,0.028935017,0.01954282,-0.0475052,-0.034435507,0.012842877,-0.045238726,0.030342882,0.030463835,-0.06891262,-0.045354925,0.06720549,0.02897311,-0.088022605,-0.001169279,0.06279709,0.047605623,0.012408862,0.04775796,0.05659921,0.01630846,0.0726464,0.0978698,0.001824263,0.06719146,-0.1498923,0.14976831,0.11696661,0.051799886,-0.015383982,0.025078498,-0.022145936,-0.0036865645,0.029662665,0.023405168,-0.0029329006,0.037510842,-0.059315257,0.07188508,0.033567216,0.083021045,-0.08935905,-0.016969386,-0.014150057,-0.03225594,-0.013935125,-0.0057289903,-0.009852632,-0.01812675,0.017896043,-0.022072077,-0.030822242,-0.042411752,0.018990036,-0.046160515,-0.009308836,-0.07212031,-0.01867975,-0.060042497,0.07099356,0.061181642,-0.049941584,0.053626277,0.015143087,0.017961733,-0.03650542,-0.08821649,-0.048811052,-0.010727523,0.03470778,-0.016471764,0.030998887,-0.0010609938,-0.07580758,-0.019054927,0.057521056,-0.048922714,0.046397183,0.022359608,0.00580874,-0.061789677,-0.047002807,0.0039530206,0.04757705,-0.004340567,0.022789478,-0.016030854,0.043919314,-0.01820688,0.04345911,0.06448709,0.037253108,-0.041605167,0.067793384,0.0033644903,0.058239445,-0.04993877,-0.05024904,-0.05485757,-0.042188466,-0.06387054,0.0575668,-0.008579166,0.012080105,-0.102168635,-0.03404742,-0.07967685,0.01173203,0.07224545,-0.08284921,0.037683126,-0.029220186,-0.0362463,-0.00042102495,-0.023075901,0.07072603,-0.009652284,0.0037491831,0