INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('73bc23cd-d716-4d38-8f04-51269587eea3', '[Tài liệu: Giới thiệu chung Viện Phát triển hợp tác quốc tế FBU] [Giới thiệu chung - Viện Phát triển hợp tác quốc tế]
### I. Quá trình hình thành và phát triển
Viện được thành lập trong bối cảnh hội nhập giáo dục quốc tế sâu rộng, nhằm hiện thực hóa chiến lược phát triển của nhà trường, nâng cao vị thế và chất lượng đào tạo. Từ khi thành lập (2025), Viện được giao quản lý đào tạo chuyên ngành **Tiếng Trung thương mại**. Đội ngũ giảng viên 100% có trình độ thạc sĩ trở lên, đào tạo trình độ Đại học chính quy.', '[-0.11135335,0.038923096,0.011395126,-0.00392754,-0.028546946,0.06492855,0.04266543,-0.06749745,0.010277963,0.06798445,0.0594534,-0.018069595,-0.028526796,0.012523774,0.020743316,-0.03173896,-0.058189448,0.05654249,-0.09568702,0.044498373,0.084812604,-0.062378187,0.04993734,-0.010231531,-0.04120236,-0.021312527,0.051607247,0.07444324,-0.056918595,-0.11555347,-0.035314824,0.023245383,-0.022529794,-0.04240139,0.048808713,-0.059021108,-0.04325663,0.062373057,0.027334116,0.05755335,-0.033052348,-0.04813995,0.02203038,-0.044163488,0.034550518,-0.013645809,-0.0989946,-0.055857882,0.0527812,0.02404554,-0.072384655,-0.0030578703,0.060212832,0.05351622,0.0041715926,0.06242501,0.014639747,0.041872054,0.079345554,0.070886225,0.019786889,0.070117034,-0.15420759,0.13929187,0.083521456,0.057727057,-0.04088733,0.012491957,-0.003061489,-0.023240931,0.0168623,0.056565683,0.0074354955,0.03604201,-0.051704366,0.06103217,0.035651423,0.07345824,-0.096145496,-0.0338711,-0.03645567,-0.017314756,-0.0010267271,-0.0023809648,-0.025223874,-0.0061868625,0.0408377,-0.019751346,-0.02926214,-0.034375686,0.006509337,-0.035947036,0.022534525,-0.039486997,-0.032927457,-0.032656424,0.03602461,0.05415405,-0.047624677,0.08599868,-0.01372824,0.029674765,-0.011653808,-0.07255124,-0.039935727,-0.006069311,0.03654553,-0.02482794,0.059771374,-0.02673104,-0.06349211,-0.043036304,0.052488297,-0.029111117,0.03910608,0.04108522,-0.01980113,-0.08460114,-0.05930569,0.037605993,0.022869023,-0.0022415412,-0.01702325,-0.03703941,0.055488504,-0.027059702,0.059814658,0.06738482,0.057157423,-0.00030065834,0.053768147,-0.0060489937,0.020971676,-0.036820576,-0.040902477,-