INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('164dd2f1-3876-46fd-9cf2-cc90c6ef24ba', '[Tài liệu: Hỏi đáp về thủ tục phúc khảo bài thi tại FBU] [Phúc khảo bài thi]
### Quy trình và quy định cụ thể
**1. Thời hạn đăng ký phúc khảo**  
Bạn chỉ có **7 ngày** (kể từ ngày điểm được công bố chính thức trên hệ thống) để đăng ký phúc khảo. Sau 7 ngày, hệ thống sẽ tự động khóa chức năng đăng ký, và bạn sẽ không thể phúc khảo bài thi đó nữa. Vì vậy, hãy **kiểm tra điểm thường xuyên** ngay sau khi kết thúc kỳ thi.

**2. Cách thức đăng ký**  
Bạn không cần nộp đơn giấy ra Phòng Khảo thí. Thay vào đó, hãy thực hiện các bước sau trên **cổng thông tin sinh viên** (https://sinhvien.fbu.edu.vn):  
- Đăng nhập bằng mã sinh viên và mật khẩu.  
- Vào mục **"Đăng ký phúc khảo"**.', '[-0.1077428,0.017829958,0.021573465,-0.0057109585,-0.051337022,0.050651155,0.057821102,-0.06278255,0.02555854,0.06894682,0.065678574,-0.00800704,-0.02495546,0.026755488,0.01446379,-0.05605209,-0.07435038,0.07807762,-0.095444694,0.054791026,0.085282266,-0.06739437,0.020170327,-0.022679016,-0.043937575,-0.019486744,0.044006992,0.04586229,-0.07254959,-0.13517408,-0.053005237,0.015454398,0.015699523,-0.056828693,0.07483275,-0.085915335,-0.02579494,0.06624246,0.040954817,0.037735846,-0.031666838,-0.049653452,0.029164588,-0.047435224,0.00737905,0.041223943,-0.05970641,-0.04962716,0.07179208,0.014419424,-0.07747249,0.01895558,0.060066953,0.04697675,0.0119957,0.053237166,0.032225966,0.04321493,0.067954436,0.064727396,0.006504795,0.06163574,-0.1567959,0.15608889,0.10547717,0.054675825,-0.01348066,0.0070687355,-0.0051327758,-0.013712339,0.011500858,0.04294881,0.00978169,0.035479985,-0.06427274,0.085474476,0.041703433,0.09327517,-0.087435834,-0.031019833,-0.019201383,-0.014083001,-0.030262023,-0.0075435624,-0.031188225,-0.02235334,0.031001989,-0.029649185,-0.022623315,-0.0392977,0.02059275,-0.03987272,-0.010268608,-0.06455025,-0.022187715,-0.064386554,0.05234109,0.07131833,-0.040152587,0.057005364,-0.0026483925,0.016350035,-0.013879642,-0.08661047,-0.051179606,-0.026562594,0.023388276,-0.031212041,0.033987973,-0.008215155,-0.05226779,-0.047154326,0.059292104,-0.038220007,0.04564799,0.05330037,0.0020757925,-0.084803455,-0.06950238,0.007908493,0.031552307,-0.022958793,0.011678922,-0.0045594536,0.05521184,-0.020324688,0.045542248,0.05674164,0.046725657,-0.016803263,0.07802316,0.004293292,0.031079972,-0.054177385,-0.040735066,-0.023932302,-0.038088378,-0.0501838,0.072169684,-0.02446526,0.011746498,-0.09569492,-0.028876707,-0.09056614,0.00040701183,0.07024209,-0.06546486,0.019545158,-0.041236475,-0.048948284,-0.0075141406,-0.016160121,0.053483628,0.02984955,0.0035257963,0.050735738,-0.0048123607,0.056326084,-0.041279074,0.013530076,-0.07061648,