INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('771eea43-c2b0-466c-8014-9205ddac0412', '[Tài liệu: Hỏi đáp về thủ tục phúc khảo bài thi tại FBU] [Phúc khảo bài thi]
### Quy trình và quy định cụ thể
- Chọn môn học muốn phúc khảo, bấm nút "Đăng ký".  
- Hệ thống sẽ xác nhận và yêu cầu bạn nộp lệ phí.

**3. Lệ phí phúc khảo**  
- Mức phí: **100.000 đồng/môn học**.  
- Sau khi đăng ký thành công, bạn cần **nộp tiền mặt** tại **Phòng Kế hoạch – Tài chính (tầng 1, cơ sở 31 Dịch Vọng Hậu)**.  
- Lưu ý: Bạn phải nộp lệ phí **ngay sau khi đăng ký** (thường trong vòng 2-3 ngày làm việc), nếu không đăng ký sẽ bị hủy.

**4. Sau khi nộp phúc khảo**  
- Phòng Khảo thí sẽ tập hợp bài thi của bạn và gửi cho Hội đồng chấm phúc khảo (gồm giảng viên khác, không phải người chấm lần đầu).', '[-0.10379179,0.009358757,0.0082713915,-0.016531875,-0.02213175,0.04239259,0.04334073,-0.058359675,0.027615638,0.07878365,0.07335708,-0.007265002,-0.007821778,0.041052163,0.0017074288,-0.04291028,-0.05912752,0.060205158,-0.0990861,0.05461936,0.10093152,-0.05122913,-0.0001335982,-0.014847795,-0.02272813,-0.026995275,0.047087543,0.047039207,-0.056409847,-0.13239005,-0.043030564,0.014709622,0.0035977797,-0.061218902,0.07324564,-0.07046254,-0.01936888,0.073437765,0.024996506,0.04740198,-0.025561826,-0.03166401,0.013034006,-0.06615777,0.0013160362,0.033698868,-0.07654807,-0.03945595,0.075507715,0.015061187,-0.09378915,0.030620446,0.07106732,0.048772123,-0.002303951,0.061589476,0.04415935,0.037589148,0.0776943,0.0720319,0.01726163,0.062247813,-0.1481747,0.16408747,0.10674473,0.055856485,0.0034264459,0.006282542,-0.007583819,-0.010412196,0.019239962,0.0383237,0.0044580656,0.028040243,-0.062776506,0.07025463,0.028849788,0.110508926,-0.10467091,-0.019669764,-0.034156565,-0.024369556,-0.023298599,0.0066581285,-0.023525942,-0.01826442,0.024701715,-0.027486075,-0.031346846,-0.050725408,0.019549299,-0.037748873,-0.006301957,-0.060028,-0.015076922,-0.049386624,0.052139867,0.062946536,-0.041586764,0.061054964,0.0058222357,0.016344568,-0.014970291,-0.086366,-0.05842478,-0.030467406,0.039299782,-0.028085502,0.037297115,0.004523569,-0.0609243,-0.036326792,0.056877512,-0.038560804,0.037305944,0.056591533,-5.4810345e-05,-0.08681735,-0.05904135,0.0060962993,0.043982547,-0.023851855,0.008695625,-0.013952558,0.037891477,-0.0051796976,0.046809863,0.07822343,0.05659776,-0.0089113265,0.08690489,-0.0058235335,0.022428486,-0.044827532,-0.039459288,-0.04162974,-0.020071968,-0.05000099,0.058616742,-0.011902387,0.010399345,-0.10381873,-0.03707307,-0.09360427,0.008792504,0.07160755,-0.07339554,0.016681256,-0.03132823,-0.0413259,-0.023211915,-0.0069041615,0.07140496