INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('2a3d6f1d-72b6-4ae1-bbbe-4ba5357a3048', '[Tài liệu: Hỏi đáp về học phí, tín chỉ, cơ sở vật chất cho sinh viên khóa 13 (2006)] [Thông tin chung cho sinh viên khóa 13 (sinh viên sinh năm 2006)]
### Câu hỏi 2: 1 tín chỉ học bao nhiêu tiền? 1 năm học bao nhiêu tín chỉ?
**Trả lời:**  
Đối với **khóa 13 (sinh viên nhập học năm 2026, sinh năm 2006)**, mức học phí đang được áp dụng là **1.000.000 đồng/tín chỉ**. Mức này có thể thay đổi theo từng năm học, nhưng thường ổn định trong toàn khóa.

Về số tín chỉ trung bình một năm:  
- Mỗi học kỳ sinh viên thường đăng ký từ 15 đến 18 tín chỉ (tùy khả năng và kế hoạch học tập).  
- Cả năm gồm 2 học kỳ chính, tổng số tín chỉ trung bình khoảng **17-18 tín chỉ/năm** đối với ngành chuẩn.  
- Một số ngành có thêm học kỳ phụ hoặc thực tập, có thể lên tới 20 tín chỉ/năm.

Lưu ý: Sinh viên có thể đăng ký ít hơn hoặc nhiều hơn tùy năng lực, nhưng tối thiểu phải đạt tiến độ theo quy định của nhà trường (thường 12-18 tín chỉ/học kỳ).', '[-0.124602884,0.011081584,0.015359049,-0.0044936636,-0.025345227,0.043554675,0.03633679,-0.07120499,0.039138857,0.08167899,0.08043366,0.0154354535,-0.014864109,0.035851263,0.008772184,-0.04110365,-0.07733259,0.05095867,-0.10971004,0.06394295,0.089977995,-0.039660882,0.0149118025,-0.03439504,-0.018610055,-0.023799911,0.04788944,0.0643719,-0.06632343,-0.13114484,-0.022492012,0.029006395,-0.017755177,-0.045253646,0.07484131,-0.0693497,-0.01485819,0.06520374,0.035638552,0.030755857,-0.00010286032,-0.041822862,0.008352092,-0.07322548,0.006179588,0.011809485,-0.0740812,-0.04874613,0.08160921,0.022695037,-0.09018771,0.014451828,0.06828438,0.072080016,-0.0031164144,0.061634373,0.040755972,0.03638053,0.08260476,0.07105009,-0.00936012,0.05594717,-0.13026129,0.16180617,0.11215284,0.070192665,-0.0171639,0.0042387466,-0.0047905096,0.0021590095,0.030095661,0.025991363,0.006100164,0.0178767,-0.06908163,0.07598021,0.023110595,0.08909075,-0.09572098,-0.053045657,-0.05098363,-0.026290983,-0.013928551,0.011923615,-0.025512436,-0.02542966,0.026598437,-0.0121655585,-0.04018104,-0.03464334,-0.0040514,-0.021371944,0.0089431675,-0.05941595,-0.014101242,-0.05251444,0.045919575,0.06635361,-0.037306312,0.07669502,0.023299495,0.02795021,-0.03888417,-0.08333966,-0.049656127,-0.017253783,0.033528473,-0.013200286,0.0469135,-0.015517894,-0.044713423,-0.051354192,0.046846613,-0.035088982,0.040929593,0.01692805,-0.016593497,-0.078248456,-0.059403826,0.0076733194,0.025478758,0.008244518,-0.00048058614,-0.025550492,0.038381394,-0.036814008,0.056490563,0.06445709,0.058675118,-0.012996291,0.04545719,-0.010189579,0.02940607,-0.024148455,-0.042735938,-0.05101376,-0.027549207,-0.040436298,0.045509454,-0.021115655,-0.008072166,-0.10299165,-0.013845945,-0.073276386,-0.006561929,0.06437659,-0.06640988,0.035393614,-0.04000473,-0.05403683,0.003619489