INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('8438abc6-ea3c-4245-b115-7e2b55d78a9d', '[Tài liệu: Hỏi đáp về Giáo dục thể chất, Quốc phòng - An ninh tại FBU] [Giáo dục thể chất và Quốc phòng - An ninh]
### Câu hỏi 1: Giáo dục thể chất và Quốc phòng - An ninh có được tính vào GPA tích lũy để xét loại bằng không?
- Nếu bạn học lại hoặc thi lại các môn này, điểm mới cũng không thay đổi GPA tích lũy.

