INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('811c373a-28ca-401a-a4f5-3b62fe9273e4', '[Tài liệu: Hỏi đáp về Giáo dục thể chất, Quốc phòng - An ninh tại FBU] [Giáo dục thể chất và Quốc phòng - An ninh]
### Câu hỏi 2: Chứng chỉ quốc phòng trong trường hợp không tìm thấy thì còn cách nào khác ngoài học lại không?
- **Trường hợp học chứng chỉ bên ngoài (các trung tâm) và nộp về trường:** Bạn cần liên hệ lại với nơi đã học để xin cấp lại bản sao. Nếu không liên hệ được, mang giấy tờ tùy thân lên Phòng CTSV&PVCD để được hướng dẫn tra cứu hồ sơ lưu.

- **Quan trọng:** Nếu bạn đã có quyết định công nhận chứng chỉ GDQP-AN (do nhà trường cấp) thì vẫn được tính là hoàn thành, không cần học lại. Chỉ khi chưa từng tham gia khóa học nào thì mới phải học lại.', '[-0.11068848,0.03275674,-0.0036202783,-0.03570674,-0.029213285,0.0761632,0.06305752,-0.06413977,-0.0046987343,0.07363145,0.065301225,-0.011436334,-0.009952626,0.022883823,0.01726264,-0.028170638,-0.070219755,0.07421742,-0.1039236,0.050034452,0.055447236,-0.038915098,0.019661112,-0.035812523,-0.036073867,-0.037260685,0.027923444,0.051336147,-0.066105925,-0.121825606,-0.056029946,0.020202326,-0.008661585,-0.051488895,0.048635487,-0.07276206,-0.029507173,0.056985345,0.03502119,0.026122725,-0.04600372,-0.042539354,0.027720269,-0.03421552,-0.015285932,0.043267474,-0.0729226,-0.034749627,0.05681682,0.023348432,-0.087208934,0.018766545,0.075899765,0.042457066,-0.0037971886,0.0759678,0.029769354,0.05214024,0.0820836,0.09596165,-0.00232149,0.07428546,-0.16864894,0.16062076,0.091867335,0.06502218,-0.032479443,0.020689169,-0.0027464437,-0.017001895,0.021590024,0.021329382,-0.017733341,0.01806758,-0.06790257,0.07620936,0.012532129,0.10585997,-0.07603926,-0.030866861,-0.04486247,-0.017529832,-0.015753753,0.021493435,-0.036776103,-0.0019262482,0.045863204,-0.00035218577,-0.036048543,-0.007870379,0.007309194,-0.036651466,-0.0024417914,-0.06972247,-0.012793223,-0.047113553,0.046807278,0.07167956,-0.05278177,0.07442725,0.01857595,0.037324846,-0.010981949,-0.06794306,-0.049600963,-0.00722277,0.034214083,-0.04079723,0.039080378,-0.005019295,-0.06348267,-0.02586327,0.07004319,-0.03144215,0.051049307,0.038975812,0.023329794,-0.06722869,-0.05053119,0.005517642,0.045036733,-0.019253485,-0.015144957,-0.011795551,0.057128552,-0.01564857,0.058030214,0.05006109,0.047489207,-0.012113056,0.07460846,-0.0074119857,0.044002067,-0.035470612,-0.04940678,-0.05079266,-0.050306972,-0.03621993,0.047239747,-0.03900619,0.0069922716,-0.1033747,-0.013890304,-0.09397075,0.0024170808,0.054153055,-0.058297