INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('8fdc1ae4-4ebf-41a9-bee7-65b5498cb254', '[Tài liệu: Hỏi đáp về Giáo dục thể chất, Quốc phòng - An ninh tại FBU] [Giáo dục thể chất và Quốc phòng - An ninh]
### Câu hỏi 3: Đi quân sự xong về em muốn xin cái chứng chỉ quốc phòng luôn thì có được không, hay trong bao lâu thì nhà trường phát?
**Trả lời:**  
Sau khi bạn hoàn thành khóa học GDQP-AN (thường kéo dài khoảng 4-8 tuần tùy đợt), nhà trường cần thời gian để tổng hợp kết quả, in ấn và cấp chứng chỉ. Thông thường:

- **Thời gian chờ:** Khoảng **6 đến 8 tháng** sau khi kết thúc khóa học, bạn sẽ được nhận chứng chỉ. Thời gian cụ thể phụ thuộc vào tiến độ xử lý của đơn vị tổ chức và phòng chức năng.

- **Bạn có thể xin trước không?** Rất tiếc, bạn không thể xin cấp ngay lập tức vì chứng chỉ chỉ được phát sau khi có đầy đủ kết quả và thông qua xét duyệt. Tuy nhiên, nếu cần xác nhận đã hoàn thành môn học để xét tốt nghiệp hoặc làm hồ sơ xin việc, bạn có thể liên hệ Phòng CTSV&PVCD để được cấp **giấy xác nhận tạm thời**.', '[-0.12561356,0.030147733,0.014206194,-0.023189476,-0.022504805,0.039089564,0.05703786,-0.06139163,0.0070375474,0.06990041,0.066226654,-0.018222531,-0.014920094,0.028798537,0.007888803,-0.025405275,-0.059824325,0.07101113,-0.118593544,0.05047449,0.0695499,-0.040134072,0.023532795,-0.02280167,-0.027438236,-0.033328563,0.027972732,0.040601548,-0.08408597,-0.11581094,-0.041841626,0.031700615,-0.0019515682,-0.07965029,0.050795607,-0.07330711,-0.02938274,0.057001155,0.035700787,0.03868589,-0.041848473,-0.030816916,0.011992526,-0.03295609,-0.005858171,0.03193628,-0.06603788,-0.05171306,0.06799885,0.019845292,-0.08547003,0.016143823,0.08714316,0.037284892,0.008572247,0.07861147,0.05649087,0.03809558,0.08804505,0.09348491,0.0035508475,0.07179546,-0.15513371,0.16360356,0.09862558,0.070736006,-0.031784866,0.03155182,-0.010423447,-8.87945e-06,0.012898896,0.032338552,-0.026975123,0.027336884,-0.079810165,0.08887236,0.020767897,0.09558892,-0.089668445,-0.035731707,-0.028262654,-0.0088981,-0.020696292,0.029495476,-0.031671487,-0.01629162,0.049159344,-0.016873414,-0.041561928,-0.022061374,0.0032638619,-0.018522078,-0.011765013,-0.06361669,-0.002402208,-0.06019175,0.049803246,0.057228528,-0.049303338,0.071218416,0.014643906,0.023472968,-0.012643188,-0.06715794,-0.047245633,-0.0065672193,0.047956247,-0.031665064,0.046748444,-0.01619016,-0.06758703,-0.033890586,0.058517095,-0.024712142,0.036386624,0.049303267,0.012591951,-0.07302987,-0.039343636,0.016659753,0.054814555,-0.028241042,0.014285457,0.0029104904,0.04060111,-0.010091298,0.056265127,0.047986392,0.04117881,-0.00785038,0.06994034,0.00029792462,0.052316878,-0.023877308,-0.04923514,-0.039795853,-0.035396,-0.0