INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('114b171f-357c-45a9-b54c-26b11263c435', '[Tài liệu: Hỏi đáp về Giáo dục thể chất, Quốc phòng - An ninh tại FBU] [Giáo dục thể chất và Quốc phòng - An ninh]
### Lưu ý chung về nghĩa vụ quân sự và GDQP-AN
> Mọi sinh viên đều phải tham gia khóa học GDQP-AN do nhà trường tổ chức. Chỉ có hai trường hợp được miễn:

1. **Có vấn đề về sức khỏe** (có giấy chứng nhận của bệnh viện cấp huyện trở lên, xác nhận không đủ sức khỏe tham gia).
2. **Đã có chứng chỉ GDQP-AN hợp lệ** từ trường đại học khác (khi chuyển trường, bạn cần nộp chứng chỉ đó về phòng đào tạo để được miễn học).

Nếu không thuộc hai trường hợp trên, bạn bắt buộc phải tham gia. Hãy sắp xếp thời gian và sức khỏe tốt để hoàn thành nhé.', '[-0.10292715,0.02629171,-0.0053513716,-0.020169571,-0.03203329,0.069773376,0.07489383,-0.06431593,0.011398375,0.07381623,0.059989817,-0.017951978,-0.000591432,0.007759772,0.008752826,-0.01997264,-0.07363317,0.061976332,-0.10594104,0.05524601,0.062148824,-0.028707113,0.022418808,-0.027709696,-0.033611268,-0.039431892,0.025661722,0.048861135,-0.076813035,-0.12471415,-0.045339596,0.011908384,0.011087034,-0.06592759,0.04455987,-0.05952753,-0.0150400065,0.06450155,0.02847961,0.023350187,-0.035919253,-0.047168672,0.007828435,-0.03656498,0.004077214,0.02733967,-0.078061685,-0.03518786,0.06082935,0.02043138,-0.06251131,0.018893505,0.075264186,0.045144435,0.0053620716,0.07293497,0.046290893,0.042316157,0.07317836,0.07398653,-0.008667432,0.06725076,-0.1604277,0.15837781,0.09371511,0.0717029,-0.036828503,0.016145479,-0.017684883,-0.011059762,0.02554335,0.020517202,-0.01485327,0.008506097,-0.076784186,0.07580402,0.028466854,0.09492756,-0.08928804,-0.0341003,-0.031276632,-0.022341812,-0.012644094,0.017756473,-0.02983403,-0.0100917285,0.050517205,-0.0020931677,-0.043731883,-0.024113689,-0.008196424,-0.040343948,-0.0054579237,-0.05408059,-0.021191536,-0.041242655,0.045633707,0.05777145,-0.04535763,0.070526965,0.013494514,0.03936023,-0.015495109,-0.081118666,-0.057785977,-0.008552806,0.04496834,-0.038036425,0.03800749,-0.0030023819,-0.0578858,-0.030487482,0.07125203,-0.01619319,0.037058137,0.032125473,0.0149139445,-0.07506704,-0.052140903,0.016717942,0.05936608,-0.022672545,-0.0048114136,-0.00042791365,0.06860676,-0.03220023,0.052254047,0.054679964,0.04940069,-0.03014155,0.061510336,-0.005249293,0.05608013,-0.0223245,-0.058356564,-0.043831557,-0.03491102,-0.03323316,0.055037193,-0.028951414,-0.0010131474,-0.10738447,-0.023501754,-0.08347545,-0.0093375165,0.06729551,-0.066705436,0.025141988,-0.02984268,-0.05568531,-0.032267947,-0.023156129,0.07576055,0.0141522