INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('f1fcaf5f-8353-46b3-abed-4341af27e6c0', '[Tài liệu: Tổ chức Tết Nguyên đán Bính Ngọ năm 2026] [CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM]
### Kính gửi:
> Các đơn vị thuộc Bộ, Sở GD&ĐT, các đại học, học viện, trường đại học, cao đẳng sư phạm, cơ sở giáo dục nghề nghiệp.

![](images/faf49efd80266ce84c3d71b51c2a1a1446928b39ffab2217a9466c766adc401e.jpg)

