INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('5a33e53d-ff68-4ff4-a8fd-695b6967824c', '[Tài liệu: Đội ngũ giảng viên Viện Ngôn ngữ nước ngoài FBU] [Đội ngũ Giảng viên - Viện Ngôn ngữ nước ngoài]
#### Tiến sĩ Trương Văn Nam
- **Thành tích:** Giải nhất Hùng biện tiếng Hán (ĐH Sư phạm Liêu Ninh); Giải ba Cầu Hán ngữ tỉnh Liêu Ninh; Giải nhất Giảng dạy tiếng Hán; Giải nhất kỹ năng giảng dạy tiếng Trung cho người nước ngoài; Giải ba Tài năng Hán ngữ “Thế giới vô tận”; Giải Ngôi sao Hán ngữ; Giải nhì toàn quốc “Kể câu chuyện tiếng Trung”; Bằng khen ĐH Sư phạm Liêu Ninh; 2 lần Bằng khen Đại sứ quán Việt Nam tại Trung Quốc; Tác giả bài nghiên cứu xuất sắc tại Hội thảo quốc tế; Danh hiệu lao động xuất sắc FBU.
