INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('ef76d33c-e191-4def-817d-b3a2e6e07610', '[Tài liệu: Rà soát thông tin sinh viên tốt nghiệp tháng 6 năm 2026] [THÔNG BÁO]
### 1. Đối với sinh viên
- **Nội dung:** Sinh viên bắt buộc truy cập Cổng thông tin sinh viên để kê khai từ 18/04/2026 đến hết 17h00 ngày 04/05/2026.
- **Sau khi kê khai:** vào mục rà soát thông tin cá nhân. Điều chỉnh theo hướng dẫn: Thông tin chung → Khảo sát sự kiện → Chọn phiếu khảo sát → Chỉnh sửa thông tin.
- **Yêu cầu:** Đối chiếu kỹ họ tên, ngày sinh, nơi sinh (theo giấy khai sinh và địa giới hành chính), số CCCD, ngày cấp, v.v.
- **Trách nhiệm:** Sinh viên chịu trách nhiệm về tính chính xác. Sai sót sau khi in bằng do lỗi kê khai sẽ không được giải quyết.', '[-0.11452881,0.01931971,0.014880186,0.014788386,-0.0029287739,0.03615796,0.052464947,-0.059957884,0.044231642,0.073630154,0.06654484,-0.015658233,-0.028669724,0.03400163,0.005180552,-0.03480194,-0.071242765,0.059165746,-0.07207027,0.04566703,0.100440666,-0.046191767,0.018071363,-0.03116103,-0.03374636,-0.026684785,0.04441313,0.06415483,-0.08325949,-0.12308036,-0.023219034,0.02741884,-0.029584518,-0.02375259,0.06860041,-0.0673551,-0.013706376,0.07382846,0.02711116,0.034895174,-0.03364805,-0.039561845,0.013447662,-0.0683542,0.0066993525,0.026473366,-0.08151227,-0.07003252,0.06472182,0.010932962,-0.07667056,-0.010417848,0.04699649,0.052377872,-0.0037930747,0.040596943,0.018831367,0.040079765,0.069794275,0.06699411,0.0017969233,0.045338366,-0.14701185,0.14011918,0.09112063,0.06777779,-0.034501053,-0.0042033764,-0.0041256878,-0.01856846,0.00926321,0.025876526,0.02677506,0.041148823,-0.062962405,0.07692511,0.020692565,0.06347723,-0.07039534,-0.057831973,-0.03521773,-0.021838047,-0.013346832,0.015841147,-0.03723117,-0.022112453,0.033037852,-0.012093366,-0.03263259,-0.04555865,0.013330149,-0.057029005,0.0037182537,-0.04792686,-0.030349502,-0.06156569,0.05170921,0.033536904,-0.046278756,0.07620002,0.008762201,0.05753783,-0.0245349,-0.08283276,-0.05391732,-0.00609824,0.04463502,-0.029571915,0.057991765,-0.0107826255,-0.052951254,-0.047370017,0.035015017,-0.048027948,0.05247431,0.037380878,-0.028402727,-0.10516667,-0.05969283,0.0149630075,0.016940229,0.019136038,-0.02107482,-0.042975392,0.040986937,-0.021429852,0.05017599,0.072539866,0.06635452,-0.015646685,0.072547674,0.0041073137,0.031867515,-0.05342052,-0.04514611,-0.06629645,-0.029914053,-0.033791486,0.07506038,-0.024545606,-0.002255565,-0.09640789,-0.037152335,-0.10478763,0.00059813337,0.058362044,-0.066088766,0.029778732,-0.058319718,-0.0825809,-0.028726745,-0.010896314,0.061821803,0.023380