INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('22ee7860-e7bf-4a4d-ace4-4a4113523dac', '[Tài liệu: Liên chi Đoàn Thanh niên Viện Ngôn ngữ nước ngoài FBU] [Liên chi Đoàn Thanh niên - Viện Ngôn ngữ nước ngoài]
### Chức năng
Liên chi Đoàn Viện Ngôn ngữ nước ngoài trực thuộc Đoàn Trường Đại học Tài chính – Ngân hàng Hà Nội, có chức năng:
- Quản lý công tác Đoàn và phụ trách các hoạt động phong trào sinh viên, thanh niên của Viện.
- Kết hợp chặt chẽ với Đoàn trường trong tổ chức và triển khai hoạt động.
- Là cầu nối thầy cô – sinh viên.
- Đẩy mạnh phong trào học tập, sáng tạo, nghiên cứu khoa học sinh viên.
- Hỗ trợ hoạt động của các Chi đoàn, trang bị kỹ năng sống cho Đoàn viên.', '[-0.07564216,0.050481685,-0.007882666,-0.023198674,-0.058520004,0.071045406,0.053224284,-0.059524607,0.012064548,0.06317545,0.055286195,-0.023963328,-0.020813562,0.0014996813,0.044880863,-0.027495608,-0.06778412,0.088503554,-0.08884345,0.04177371,0.0520084,-0.049292434,0.019062528,-0.027157124,-0.038692623,-0.04776625,0.010794182,0.05034358,-0.060868867,-0.10572059,-0.06139453,0.037182234,-0.013896856,-0.04637886,0.047691166,-0.052688066,-0.03228475,0.058043562,0.047978003,0.0509412,-0.051673844,-0.03317828,0.040727258,-0.043657593,0.015511361,0.021897618,-0.08895747,-0.04002546,0.06651254,0.0137903495,-0.06254543,0.006464397,0.045651652,0.033647675,0.010870333,0.059313186,0.02427779,0.013116249,0.07879522,0.090281084,0.02344973,0.055899892,-0.17716512,0.1469916,0.10427906,0.05581849,-0.027276527,0.03592257,-0.017107906,-0.02892142,0.025942434,0.03472113,0.011112895,0.05306123,-0.05809651,0.08455528,0.04530985,0.06942949,-0.08697509,-0.012122624,-0.020410849,-0.013314888,-0.032450497,0.018914878,-0.024091838,-0.026127964,0.034779128,-0.03268771,-0.032596927,-0.010922153,-0.009030784,-0.03450096,0.011172728,-0.057929784,-0.021707349,-0.043739576,0.044419304,0.058400564,-0.061792348,0.09312941,0.0026424027,0.024123814,-0.016844917,-0.08232456,-0.05222667,-0.011820277,0.021372426,-0.036136657,0.06813294,0.008553894,-0.08817065,-0.04915118,0.034106746,-0.04587237,0.0702423,0.043226283,-0.006523294,-0.055085305,-0.039470855,0.012902389,0.026730886,-0.0044637737,0.0074646682,-0.025312768,0.068951055,-0.03341375,0.06603575,0.059599947,0.066604696,-0.035235967,0.07314699,-0.017131438,0.01418433,-0.018947586,-0.043533478,-0.035468742,-0.0395103,-0.0322644,0.056106213,-0.032111056,0.009258968,-0.09618674,-0.031470865,-0.08489661,0.005178981,0.030290876,-0.07991994,0.044550624,-0.03422611,-0.067371495,0.010462007,-0.012808697,0.09147517,-0.013758136,-0.0042639785,0.012882836,0.0052594743,0.055252902,-