INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('e5893127-aba0-4e63-b89f-dd41bde5df41', '[Tài liệu: Rà soát các điều kiện xét tốt nghiệp đợt tháng 6 năm 2026] [THÔNG BÁO]
### 2. Nội dung rà soát
Sinh viên kiểm tra đầy đủ các điều kiện sau:

- Tích lũy đủ học phần, số tín chỉ.
- Điểm trung bình chung tích lũy toàn khóa ≥ 2.0.
- Đạt chuẩn đầu ra ngoại ngữ.
- Có chứng chỉ GDQP-AN và hoàn thành các học phần GDTC.
- Hoàn thành nghĩa vụ học phí, phí, lệ phí.
- Các điều kiện khác theo quy định hiện hành.', '[-0.10360776,0.035817627,0.014990225,-0.004217525,-0.017892929,0.054926593,0.053362228,-0.04837897,0.025895538,0.08033691,0.072387606,-0.015405722,-0.034158837,0.05284814,0.026300987,-0.04670758,-0.048461366,0.07257397,-0.073316894,0.041874725,0.10477646,-0.062107973,0.013314954,-0.048838034,-0.012878997,-0.0421417,0.02802598,0.08618533,-0.06832553,-0.12699193,-0.04712651,0.026346013,-0.023036906,-0.036123663,0.062966935,-0.07310368,-0.030757021,0.050297756,0.008593635,0.037089646,-0.022085352,-0.053031545,0.004378006,-0.061629746,0.014193018,0.0024565726,-0.09527503,-0.056089893,0.050629836,0.014986914,-0.073414445,-0.00032126883,0.05513373,0.054060623,0.0019664692,0.03335461,0.0066889217,0.01899209,0.05913604,0.071748115,-0.0039635706,0.054866627,-0.11536326,0.1549292,0.089159176,0.07064979,-0.024242882,0.005745571,-0.012513173,-0.014650417,0.019178703,0.035773832,0.0027168854,0.034089368,-0.0364871,0.08049385,0.01751702,0.084510915,-0.07330005,-0.049562532,-0.039876606,-0.019177277,-0.007268975,0.017513432,-0.014073001,-0.019673815,0.017191544,-0.03074301,-0.028482826,-0.026931005,0.011413807,-0.040720757,0.004735555,-0.04914928,-0.023586895,-0.059639376,0.06313172,0.027415464,-0.028292451,0.093433775,0.0020794848,0.041350257,-0.041248653,-0.06300765,-0.037943505,-0.021038407,0.04324476,-0.031421594,0.056416947,-0.0076537053,-0.046736754,-0.033737443,0.0229222,-0.02220005,0.041540064,0.022062913,-0.029079815,-0.09871139,-0.015179772,0.016076842,0.0118661765,0.02505823,-0.014421744,-0.0395285,0.05498424,-0.032250408,0.028063271,0.060697448,0.057347845,-0.007546939,0.059346303,-0.028678682,-0.006774308,-0.019679638,-0.027982319,-0.06436763,-0.036126822,-0.022177162,0.047011398,-0.016886454,-0.024564965,-0.10986324,-0.01979791,-0.09909459,0.006239252,0.0697484,-0.07261969,0.024901643,-0.047575165,-0.088679895,-0.015420647,-0.022970585,0.07415081,0.000513695,0.0145973945,0.02038121,-0.028812587,0.08897783,-0.04625406,0