#### 1. Sứ mệnh
> Đào tạo nguồn nhân lực chất lượng cao trong lĩnh vực Tài chính, Ngân hàng, Kế toán, Kiểm toán, Quản trị kinh doanh và Kinh doanh thương mại; nghiên cứu, chuyển giao khoa học về quản trị và kinh doanh; tham gia hoạch định chiến lược, chính sách cho doanh nghiệp và tổ chức xã hội.', '[-0.06640538,0.048038993,0.0015758581,0.0006900741,-0.04439147,0.056015514,0.06791978,-0.058250718,0.00779085,0.07922535,0.076153964,-0.053259064,-0.023059657,0.01763284,0.02509218,-0.011629003,-0.04516022,0.07540932,-0.07202737,0.04190478,0.06745039,-0.048723556,0.014180402,-0.035348393,-0.018935349,-0.04018759,-0.004047453,0.05009549,-0.06677295,-0.09826012,-0.050225712,0.049017962,-0.0023813974,-0.04894813,0.06871889,-0.069766864,-0.03166249,0.04507536,0.04759459,0.017401835,-0.059940215,-0.014463045,0.03375358,-0.0471265,0.026944112,0.034269392,-0.070565656,-0.06993028,0.07022596,0.030384248,-0.055715438,0.0034876424,0.04268199,0.037221767,0.024151757,0.04377987,0.028173251,0.009254002,0.0719112,0.09652618,0.030247623,0.081313424,-0.1507398,0.13908997,0.07929718,0.07747854,-0.02319563,0.008628934,-0.046835963,-0.009052903,0.029150182,0.039159805,-0.0020110155,0.03635817,-0.06804758,0.07254479,0.04762275,0.084915884,-0.08103876,-0.01763841,-0.023930218,-0.013235345,-0.018479897,0.01862485,-0.03124458,0.014248479,0.022712745,-0.045161184,-0.02634652,-0.0060208966,-0.038099196,-0.02608768,0.044784974,-0.013533054,-0.03333765,-0.0534747,0.016610904,0.05153714,-0.018747728,0.09827763,0.027648615,0.05889495,-0.035081092,-0.087117665,-0.052547283,-0.025449095,0.026775803,-0.023487575,0.053395193,-0.015234086,-0.066256434,-0.046110313,0.027752552,-0.022394747,0.039850615,0.05524802,-0.011263426,-0.06744593,-0.018623328,0.014552605,0.056784756,0.0039078244,0.025902826,-0.02144983,0.0516019,-0.0446088,0.086468935,0.054547977,0.072203696,-0.024055023,0.0443746,-0.008095576,-0.008518164,-0.04603453,-0.057793148,-0.06179053,-0.0151008135,-0.0377882,0.0427685,-0.054868788,-0.002193355,-0.12234134