INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('831c5d7b-4707-4f48-b207-63f3bf492a8c', '[Tài liệu: Sứ mệnh, tầm nhìn và giá trị cốt lõi của Trường Đại học Tài chính - Ngân hàng Hà Nội] [Tầm nhìn - Sứ mệnh - Giá trị cốt lõi]
#### 3. Các giá trị cốt lõi
- **Trọng giá trị tri thức và thượng tôn đạo đức nghề nghiệp:** Môi trường giáo dục sáng tạo, đào tạo con người có năng lực chuyên môn cao và trách nhiệm xã hội.
- **Khuyến khích sáng tạo và nuôi dưỡng sự say mê:** Nơi nuôi dưỡng niềm say mê của giảng viên, nhân viên, sinh viên; nền tảng đổi mới và đột phá thương hiệu.
- **Tôn trọng sự khác biệt và coi trọng hợp tác:** Cộng hưởng sức mạnh hợp tác với sự khác biệt, tạo hợp lực mạnh mẽ; đề cao tự chủ học thuật.
- **Coi trọng chất lượng là uy tín và là danh dự:** Chất lượng trong đào tạo là con đường và mục tiêu để đạt tầm khu vực và quốc tế.', '[-0.077473044,0.030514816,0.003360818,-0.0032996838,-0.04968432,0.06073462,0.06458056,-0.05413935,0.019825866,0.06309847,0.071523406,-0.037796024,-0.012390007,0.0136198215,0.025127426,-0.022730665,-0.061718818,0.087745205,-0.10164208,0.06340562,0.063952744,-0.038284834,0.008918608,-0.02846017,-0.03022947,-0.017552001,0.028373579,0.059697624,-0.07447376,-0.11239443,-0.04403259,0.043767493,-0.01497695,-0.04302101,0.045718763,-0.07720023,-0.04462234,0.04765607,0.036268942,0.032511752,-0.050868362,-0.022306703,0.026685823,-0.045547426,0.010300746,0.028562874,-0.064371005,-0.04844562,0.06371589,0.02721782,-0.09287444,0.021106219,0.041779295,0.033934098,0.012868784,0.059888065,0.035058174,0.026036402,0.08626696,0.090917595,0.015460215,0.059454046,-0.16581473,0.15337992,0.09280675,0.079659365,-0.04328751,0.030406768,-0.029782996,-0.0010620696,0.016178722,0.049470108,0.002747629,0.0294188,-0.06735101,0.07529375,0.039749496,0.086244054,-0.07762298,-0.029400356,-0.010135318,-0.010652736,-0.025383534,-0.0013271386,-0.030883979,-0.03335917,0.029593814,-0.020030467,-0.03360143,-0.02236458,-0.009417374,-0.04877491,0.014909599,-0.03783867,-0.011460021,-0.061419535,0.028527975,0.077553466,-0.054953616,0.07303984,0.020671543,0.027850006,-0.00663104,-0.07801318,-0.05059062,-0.025346579,0.030454094,-0.033193983,0.05795197,0.006606083,-0.043385126,-0.035645083,0.039675314,-0.05238762,0.040505897,0.05089636,0.029917493,-0.072781004,-0.033045594,0.02110665,0.026484469,-0.018096102,0.009840043,-0.01934927,0.043854237,-0.03114642,0.07413024,0.054089222,0.054861862,-0.035147484,0.073490016,0.0018132012,0.047190897,-0.049519964,-0.055292595,-0.056172755,-0.044666555,-0.06263956,0.066293985,-0.03524807,0.027388781,-0.08031138,-0.04354095,-0.07266819,0.006049066,0.034797534,-0.066658884,0.019025577,-0.05954557,-0.04868904,-0.007218272,-0.021096993,0.0747897,-0