INSERT INTO public.document_chunks (id, content, embedding, source_file, chunk_index, doc_type, year, title, section, created_at, parent_id) VALUES ('40c49428-cc65-4bf8-aa6d-f6efb18ec677', '[Tài liệu: Sứ mệnh, tầm nhìn và giá trị cốt lõi của Trường Đại học Tài chính - Ngân hàng Hà Nội] [Tầm nhìn - Sứ mệnh - Giá trị cốt lõi]
#### 2. Mục tiêu cụ thể
| Lĩnh vực | Mục tiêu |
|----------|----------|
| **Đào tạo** | 2016: có đào tạo thạc sĩ; 2020: có đào tạo tiến sĩ. 2030: 5 ngành đạt AUN-QA. Quy mô: 2030 đạt 10.500 SV; 2040 đạt >17.500 SV và học viên sau đại học. |
| **Khoa học - công nghệ** | Trở thành một trong những trung tâm nghiên cứu - tư vấn về chiến lược và chính sách kinh tế quốc gia. |
| **Hợp tác quốc tế** | 2030: tất cả Khoa chuyên môn có liên kết đào tạo và nghiên cứu quốc tế trực tiếp. 2040: liên kết đào tạo tất cả cấp độ với các trường đại học lớn trong khối G20 và sang các nước trong khu vực. |
| **Nhân lực** | 2030: 400 CBGV, >70% giảng viên (75% thạc sĩ, 25% tiến sĩ). 2040: 700 CBGV, >80% giảng viên (70% thạc sĩ, 30% tiến sĩ). |
| **Cơ sở vật chất** | Hiện đại, đồng bộ, quy mô lớn trên không gian ~11ha. |
| **Giá trị văn hóa** | Xây dựng văn hóa Đại học kết hợp truyền thống và hiện đại. |', '[-0.101716705,0.02663538,0.006042801,-0.0100767575,-0.0023555842,0.05856003,0.031197248,-0.07581803,0.022991797,0.060627334,0.07156922,-0.042652465,-0.032851316,0.019355765,0.0028468354,-0.02473658,-0.06447711,0.04036711,-0.103935204,0.06276286,0.091455474,-0.052559935,0.007124939,-0.039511148,-0.009434627,-0.030556856,0.040676415,0.057992026,-0.0932985,-0.124289826,-0.032707866,0.02005802,-0.019898815,-0.0339774,0.057880897,-0.0787849,-0.019410914,0.06458416,0.048058424,0.01970804,-0.020966534,-0.026596375,0.0127775045,-0.043180928,0.018883986,0.0004909958,-0.073935315,-0.065073304,0.06841707,0.011455529,-0.08875949,0.010639252,0.04894596,0.03894008,0.014088646,0.06345842,0.03212971,0.027846497,0.10379065,0.081746474,0.033566754,0.06372294,-0.14687286,0.14369108,0.100475095,0.045837034,-0.022719767,0.014427395,0.004013092,-0.003976169,0.018381556,0.017415076,-0.0076246005,0.03652434,-0.071329385,0.06403416,0.04703141,0.09987413,-0.0842968,-0.04046569,-0.016390026,-0.009604723,-0.0021532502,-0.0020112582,-0.014326325,-0.016562007,0.046806414,-0.028769359,-0.040184323,-0.04589856,-0.00941678,-0.043411978,0.035902575,-0.044622846,-0.020282056,-0.035925623,0.041020073,0.054278884,-0.02454858,0.07485432,0.013415309,0.022323532,-0.0066321017,-0.07496642,-0.049101617,-0.015013817,0.03004844,-0.020598935,0.046099782,-0.0160686,-0.045078885,-0.040532455,0.06519414,-0.012870689,0.039770026,0.026530385,-0.019347664,-0.07119106,-0.05258274,0.019097462,0.04627707,0.009134949,0.0050422973,-0.011328713,0.033974968,-0.037266217,0.056634825,0.047414705,0.05446992,-0.00047735625,0.06328807,-0.0016915159,0.038213234,-0.019608308,-0.047763333,-0.047667775,-0.03107454,-0.0630762,0.059572283,-0.047451835,0.011338381,-0.074374504,-0.021200038,-0.09189468,0.0010100042,0.06051013,-0.091006085,0.017419016,-0.046887897,-0.06004287,-0.0014778238,-0.015526696,0.07652487,-0.018792316,-0.018038275,0.012244507